<?php
namespace Tests\Feature;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class WorldMapSchemaTest extends TestCase{use RefreshDatabase;public function test_schema_uses_json_innodb_and_expected_indexes(){$this->assertTrue(Schema::hasColumns('world_maps',['world_id','region_id','image_path','version','is_default']));$this->assertTrue(Schema::hasColumns('world_map_areas',['polygon_points','action_type','available_from','version']));$maps=DB::selectOne("SELECT ENGINE,TABLE_COLLATION FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='world_maps'");$areas=DB::selectOne("SELECT ENGINE,TABLE_COLLATION FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='world_map_areas'");$this->assertSame('InnoDB',$maps->ENGINE);$this->assertSame('utf8mb4_unicode_ci',$areas->TABLE_COLLATION);$column=DB::selectOne("SHOW COLUMNS FROM world_map_areas WHERE Field='polygon_points'");$this->assertSame('json',$column->Type);}}
